class Solution {
    public int strongPasswordChecker(String password) {
        int missingType = 3;
        boolean hasLower = false, hasUpper = false, hasDigit = false;
        int repeatCount = 0, repeatChar = 0;
        for (int i = 0; i < password.length(); i++) {
            char c = password.charAt(i);
            if (Character.isLowerCase(c)) hasLower = true;
            if (Character.isUpperCase(c)) hasUpper = true;
            if (Character.isDigit(c)) hasDigit = true;
            if (i > 0 && c == password.charAt(i - 1)) {
                repeatCount++;
                repeatChar = c;
            } else {
                repeatCount = 1;
            }
            if (repeatCount == 2) {
                missingType += 1;
            }
        }
        if (!hasLower) missingType--;
        if (!hasUpper) missingType--;
        if (!hasDigit) missingType--;
        int add = Math.max(0, 6 - password.length());
        int delete = Math.max(0, password.length() - 20);
        int res = add + delete + missingType;
        if (password.length() < 6) res += repeatCount;
        else res += Math.max(repeatCount, missingType);
        return res;
    }
}
